};

export default function LocationsPage() {
  return <Locations />;
}

// 在庫ロケーション管理 / 棚卸移動 — seed data + domain helpers.
// A standing inventory-location screen: bins with capacity/fill, SKUs, and moves.

export type Zone = "A" | "B" | "C" | "D";
export type TempClass = "常温" | "冷蔵" | "冷凍" | "危険物";

export interface Sku {
  sku: string;
  jan: string;
  name: string;
}

export interface Location {
  /** 棚番 e.g. "A-12-03" */
  id: string;
  zone: Zone;
  /** 通路 (aisle) */
  aisle: string;
  tempClass: TempClass;
  /** 格納SKU (a bin holds at most one SKU in this model; empty bins have null) */
  sku: Sku | null;
  /** 在庫数 (current on-hand units) */
  onHand: number;
  /** 容量 (max units the bin holds) */
  capacity: number;
  /** 最終移動日 (ISO date) — drives 滞留 detection. null = never moved. */
  lastMovedAt: string | null;
}

export interface MoveRecord {
  id: string;
  at: string; // ISO datetime
  from: string;
  to: string;
  sku: Sku;
  qty: number;
  reason: string;
}

