  { id: "C-06-01", zone: "C", aisle: "06", tempClass: "冷蔵", sku: SKUS[4], onHand: 58, capacity: 60, lastMovedAt: daysAgo(1) },
  { id: "C-06-02", zone: "C", aisle: "06", tempClass: "冷蔵", sku: SKUS[4], onHand: 12, capacity: 60, lastMovedAt: daysAgo(2) },
  { id: "C-07-01", zone: "C", aisle: "07", tempClass: "冷凍", sku: SKUS[3], onHand: 75, capacity: 75, lastMovedAt: daysAgo(4) },
  { id: "C-07-02", zone: "C", aisle: "07", tempClass: "冷凍", sku: SKUS[3], onHand: 9, capacity: 75, lastMovedAt: daysAgo(41) },
