export const MOVE_HISTORY: MoveRecord[] = [
  { id: "MV-0007", at: "2026-06-23T08:42", from: "A-02-02", to: "A-02-01", sku: SKUS[5], qty: 30, reason: "consolidate" },
  { id: "MV-0006", at: "2026-06-22T17:10", from: "C-06-02", to: "C-06-01", sku: SKUS[4], qty: 8, reason: "consolidate" },
  { id: "MV-0005", at: "2026-06-22T11:25", from: "A-01-02", to: "A-01-01", sku: SKUS[1], qty: 12, reason: "rebalance" },
