export const MOVE_REASONS: { value: string; label: string }[] = [
  { value: "consolidate", label: "棚詰め（集約）" },
  { value: "rebalance", label: "平準化（過充填の解消）" },
  { value: "relocate", label: "ロケーション変更" },
  { value: "slotting", label: "スロッティング最適化" },
];

// ---- domain helpers ----

export type FillTone = "success" | "warning" | "destructive";
export type BinState = "空" | "通常" | "満杯間近" | "満杯";

/** fill % = onHand / capacity, clamped 0–100. */
export function fillPct(onHand: number, capacity: number): number {
  if (capacity <= 0) return 0;
  return Math.min(100, Math.max(0, Math.round((onHand / capacity) * 100)));
}

/** Threshold tone: <80 ok(success), 80–99 warning, 100 over(destructive). */
export function fillTone(pct: number): FillTone {
  if (pct >= 100) return "destructive";
  if (pct >= 80) return "warning";
  return "success";
}

export function binState(onHand: number, capacity: number): BinState {
  if (onHand <= 0) return "空";
  const pct = fillPct(onHand, capacity);
  if (pct >= 100) return "満杯";
  if (pct >= 80) return "満杯間近";
  return "通常";
}

export function isStale(loc: Location): boolean {
  if (!loc.sku || loc.onHand <= 0 || !loc.lastMovedAt) return false;
  const last = new Date(loc.lastMovedAt + "T00:00:00+09:00").getTime();
  const diffDays = (today.getTime() - last) / 86_400_000;
  return diffDays > STALE_DAYS;
}

export function daysSinceMoved(loc: Location): number | null {
  if (!loc.lastMovedAt) return null;
  const last = new Date(loc.lastMovedAt + "T00:00:00+09:00").getTime();
  return Math.floor((today.getTime() - last) / 86_400_000);
}

export interface Kpis {
  total: number;
  avgFill: number; // %
  nearFull: number; // 満杯間近 + 満杯
  empty: number;
  stale: number;
}

export function computeKpis(locs: Location[]): Kpis {
  const total = locs.length;
  // avg fill across bins that have a defined capacity
  const fills = locs.map((l) => fillPct(l.onHand, l.capacity));
  const avgFill = total > 0 ? Math.round(fills.reduce((a, b) => a + b, 0) / total) : 0;
  const nearFull = locs.filter((l) => {
    const s = binState(l.onHand, l.capacity);
    return s === "満杯間近" || s === "満杯";
  }).length;
  const empty = locs.filter((l) => l.onHand <= 0).length;
  const stale = locs.filter(isStale).length;
  return { total, avgFill, nearFull, empty, stale };
}

export interface ZoneRollup {
  zone: Zone;
  bins: number;
  avgFill: number;
  onHand: number;
  capacity: number;
}

export function zoneRollups(locs: Location[]): ZoneRollup[] {
  const zones: Zone[] = ["A", "B", "C", "D"];
  return zones
    .map((zone) => {
      const inZone = locs.filter((l) => l.zone === zone);
      const onHand = inZone.reduce((a, l) => a + l.onHand, 0);
      const capacity = inZone.reduce((a, l) => a + l.capacity, 0);
      return {
        zone,
        bins: inZone.length,
        avgFill: capacity > 0 ? Math.round((onHand / capacity) * 100) : 0,
        onHand,
        capacity,
      };
    })
    .filter((z) => z.bins > 0);
}

"use client";

import * as React from "react";
import { Progress, cn, formatNumber } from "@gunjo/ui";
import { fillPct, fillTone, type FillTone } from "./data";

const TONE_TEXT: Record<FillTone, string> = {
  success: "text-success",
  warning: "text-warning",
  destructive: "text-destructive",
};

export interface LocationMeterProps {
  onHand: number;
  capacity: number;
  /** Units arriving from a pending move — previewed as a ghost segment on top. */
  incoming?: number;
  /** Compact inline variant for a table cell (thinner bar, % inline). */
  compact?: boolean;
  /** Accessible-name prefix, e.g. the 棚番. */
  name?: string;
  className?: string;
}

/**
 * Capacity / fill meter built on `Progress` + its `tone` prop. The library has
 * no capacity-aware Meter (threshold→tone, current+incoming overlay, inline
 * variant), so this composes those three jobs around Progress. (See FINDINGS.)
 */
export function LocationMeter({
  onHand,
  capacity,
  incoming = 0,
  compact = false,
  name,
  className,
}: LocationMeterProps) {
  const pct = fillPct(onHand, capacity);
  const afterPct = fillPct(onHand + incoming, capacity);
  const tone = fillTone(incoming > 0 ? afterPct : pct);
  const free = Math.max(0, capacity - onHand - Math.max(0, incoming));
  const prefix = name ? `${name} ` : "";
  const valueText =
    incoming > 0
      ? `${prefix}充填 ${onHand}＋${incoming} / ${capacity} 点（移動後 ${afterPct}%）、空き ${free} 点`
      : `${prefix}充填 ${onHand} / ${capacity} 点（${pct}%）、空き ${free} 点`;

  return (
    <div className={cn("flex w-full flex-col gap-1", className)}>
      <div className="flex items-center justify-between gap-2 text-xs">
        <span className="text-muted-foreground">{compact ? "充填率" : "容量・充填率"}</span>
        <span className={cn("font-medium tabular-nums", TONE_TEXT[tone])}>
          {pct}%
          {incoming > 0 ? (
            <span className="ml-1 font-normal text-foreground">→ {afterPct}%</span>
          ) : null}
          <span className="ml-1 font-normal text-muted-foreground">
            空き {formatNumber(free)}
          </span>
        </span>
      </div>
      <div className="relative">
        <Progress
          value={onHand}
          max={capacity || 1}
          tone={tone}
          label={valueText}
          valueText={valueText}
          className={compact ? "h-1.5" : "h-2.5"}
        />
        {incoming > 0 ? (
          // ghost "incoming" segment layered after the committed fill
          <div
            aria-hidden="true"
            className={cn(
              "pointer-events-none absolute inset-y-0 overflow-hidden rounded-full",
              compact ? "h-1.5" : "h-2.5"
            )}
            style={{
              left: `${Math.min(100, pct)}%`,
              width: `${Math.max(0, afterPct - pct)}%`,
            }}
          >
            <div className="h-full w-full animate-pulse rounded-full bg-info/70" />
          </div>
        ) : null}
      </div>
    </div>
  );
}

"use client";

import * as React from "react";
import {
  IconBuildingWarehouse,
  IconMapPin,
  IconSearch,
  IconArrowRight,
  IconAlertTriangle,
  IconCircleCheck,
  IconArrowsExchange,
  IconStack2,
  IconPackage,
  IconFileExport,
  IconEdit,
  IconClockHour4,
  IconSnowflake,
  IconFlame,
  IconBox,
  IconX,
  IconHistory,
} from "@tabler/icons-react";
import {
  Alert,
  AlertDescription,
  AlertTitle,
  Badge,
  Button,
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
  DataTable,
  Delta,
