  type ScanGateStage,
} from "@gunjo/ui";

import {
  LOCATIONS,
  MOVE_HISTORY,
  MOVE_REASONS,
  STALE_DAYS,
  binState,
  computeKpis,
  daysSinceMoved,
  fillPct,
  isStale,
  zoneRollups,
  type BinState,
  type Location,
  type MoveRecord,
  type TempClass,
  type Zone,
} from "./data";
import { LocationMeter } from "./LocationMeter";

const STATE_BADGE: Record<BinState, BadgeProps["variant"]> = {
  空: "outline",
  通常: "success",
  満杯間近: "warning",
  満杯: "destructive",
};

const TEMP_ICON: Record<TempClass, React.ReactNode> = {
  常温: <IconBox className="h-3 w-3" aria-hidden="true" />,
  冷蔵: <IconSnowflake className="h-3 w-3" aria-hidden="true" />,
  冷凍: <IconSnowflake className="h-3 w-3" aria-hidden="true" />,
  危険物: <IconFlame className="h-3 w-3" aria-hidden="true" />,
};

const ZONE_LABEL: Record<Zone, string> = {
  A: "ゾーンA（飲料）",
  B: "ゾーンB（食品・日用品）",
  C: "ゾーンC（チルド/冷凍）",
  D: "ゾーンD（危険物）",
};

export default function Locations() {
  // ---- master data (mutable on a committed move) ----
  const [locations, setLocations] = React.useState<Location[]>(LOCATIONS);
  const [history, setHistory] = React.useState<MoveRecord[]>(MOVE_HISTORY);

  // ---- filters ----
  const [zoneFilter, setZoneFilter] = React.useState<"all" | Zone>("all");
  const [tempFilter, setTempFilter] = React.useState<"all" | TempClass>("all");
  const [stateFilter, setStateFilter] = React.useState<"all" | BinState | "滞留">("all");
  const [skuQuery, setSkuQuery] = React.useState("");

  // ---- move composer ----
  const [moveOpen, setMoveOpen] = React.useState(false);
  const [fromId, setFromId] = React.useState<string>("");
  const [toId, setToId] = React.useState<string>("");
  const [moveQty, setMoveQty] = React.useState(1);
  const [reason, setReason] = React.useState(MOVE_REASONS[0].value);
  const [moveResult, setMoveResult] = React.useState<{
    ok: boolean;
    message: string;
  } | null>(null);
  const scanRef = React.useRef<import("@gunjo/ui").ScanGateHandle>(null);

  // ---- bin editor ----
  const [editTarget, setEditTarget] = React.useState<Location | null>(null);
  const [editCapacity, setEditCapacity] = React.useState(0);
  const [editTemp, setEditTemp] = React.useState<TempClass>("常温");

  const byId = React.useCallback(
    (id: string) => locations.find((l) => l.id === id) ?? null,
    [locations]
  );

  const from = byId(fromId);
  const to = byId(toId);

  // ---- derived KPIs / rollups (recompute from live data) ----
  const kpis = React.useMemo(() => computeKpis(locations), [locations]);
  const rollups = React.useMemo(() => zoneRollups(locations), [locations]);

  // ---- filtered rows ----
  const rows = React.useMemo(() => {
    const q = skuQuery.trim().toLowerCase();
    return locations.filter((l) => {
      if (zoneFilter !== "all" && l.zone !== zoneFilter) return false;
      if (tempFilter !== "all" && l.tempClass !== tempFilter) return false;
      if (stateFilter === "滞留") {
        if (!isStale(l)) return false;
      } else if (stateFilter !== "all") {
        if (binState(l.onHand, l.capacity) !== stateFilter) return false;
      }
      if (q) {
        const hay = [l.id, l.sku?.sku, l.sku?.jan, l.sku?.name]
          .filter(Boolean)
          .join(" ")
          .toLowerCase();
        if (!hay.includes(q)) return false;
      }
      return true;
    });
  }, [locations, zoneFilter, tempFilter, stateFilter, skuQuery]);

  // ---- SKU lookup (在庫照会) — where is a SKU stored ----
  const skuMatches = React.useMemo(() => {
    const q = skuQuery.trim().toLowerCase();
    if (!q) return [];
    return locations
      .filter(
        (l) =>
          l.sku &&
          l.onHand > 0 &&
          [l.sku.sku, l.sku.jan, l.sku.name]
            .join(" ")
            .toLowerCase()
            .includes(q)
      )
      .sort((a, b) => b.onHand - a.onHand);
  }, [locations, skuQuery]);

  // ---- move validation ----
  const validation = React.useMemo(() => {
    if (!from)
      return { ok: false, level: "info" as const, msg: "移動元の棚を選択またはスキャンしてください。" };
    if (!from.sku || from.onHand <= 0)
      return { ok: false, level: "destructive" as const, msg: `${from.id} は空棚です。在庫のある棚を選んでください。` };
    if (!to)
      return { ok: false, level: "info" as const, msg: "移動先の棚を選択またはスキャンしてください。" };
    if (to.id === from.id)
      return { ok: false, level: "destructive" as const, msg: "移動元と移動先が同じ棚です。" };
    // destination must hold the same SKU or be empty
    if (to.sku && to.sku.sku !== from.sku.sku)
      return {
        ok: false,
        level: "destructive" as const,
        msg: `移動先 ${to.id} には別の商品（${to.sku.name}）が格納されています。集約できません。`,
      };
    if (moveQty <= 0)
      return { ok: false, level: "info" as const, msg: "移動数量を入力してください。" };
    if (moveQty > from.onHand)
      return {
        ok: false,
        level: "destructive" as const,
        msg: `移動元の在庫 ${from.onHand} 点を超える数量は移動できません。`,
      };
    const destFree = to.capacity - to.onHand;
    if (moveQty > destFree)
      return {
        ok: false,
        level: "warning" as const,
        msg: `移動先 ${to.id} の空き容量は ${destFree} 点です。容量を超える移動はできません。`,
      };
    const afterFrom = from.onHand - moveQty;
    const consolidates = afterFrom === 0;
    return {
      ok: true,
      level: "success" as const,
      msg: consolidates
        ? `${from.sku.name} を ${formatNumber(moveQty)} 点 ${from.id} → ${to.id} に集約します（移動元は空棚になります）。`
        : `${from.sku.name} を ${formatNumber(moveQty)} 点 ${from.id} → ${to.id} に移動します。`,
    };
  }, [from, to, moveQty]);

  // candidate destinations for the currently-selected source SKU
  const destOptions = React.useMemo(() => {
    if (!from || !from.sku) return locations.filter((l) => l.id !== fromId);
    return locations
      .filter(
        (l) =>
          l.id !== fromId &&
          (l.onHand <= 0 || l.sku?.sku === from.sku!.sku) &&
          l.capacity - l.onHand > 0
      )
      .sort((a, b) => b.capacity - b.onHand - (a.capacity - a.onHand));
  }, [locations, from, fromId]);

  function openMoveFor(loc: Location) {
    setFromId(loc.id);
    setToId("");
    setMoveQty(loc.onHand > 0 ? Math.min(loc.onHand, Math.max(1, Math.floor(loc.onHand / 2))) : 1);
    setMoveResult(null);
    setMoveOpen(true);
    scanRef.current?.reset();
  }

  function commitMove() {
    if (!validation.ok || !from || !from.sku || !to) return;
    const sku = from.sku;
    const nowIso = new Date().toISOString().slice(0, 16);
    setLocations((prev) =>
      prev.map((l) => {
        if (l.id === from.id) {
          const remaining = l.onHand - moveQty;
          return {
            ...l,
            onHand: remaining,
            sku: remaining > 0 ? l.sku : null,
            lastMovedAt: nowIso.slice(0, 10),
          };
        }
        if (l.id === to.id) {
          return {
            ...l,
            onHand: l.onHand + moveQty,
            sku: l.sku ?? sku,
            lastMovedAt: nowIso.slice(0, 10),
          };
        }
        return l;
      })
    );
    setHistory((prev) => [
      {
        id: `MV-${String(8 + prev.length).padStart(4, "0")}`,
        at: nowIso,
        from: from.id,
        to: to.id,
        sku,
        qty: moveQty,
        reason,
      },
      ...prev,
    ]);
    setMoveResult({
      ok: true,
      message: `移動完了：${sku.name} を ${formatNumber(moveQty)} 点 ${from.id} → ${to.id}。`,
    });
    // reset the composer for the next move but keep the sheet open to show the toast
    setFromId("");
    setToId("");
    setMoveQty(1);
    scanRef.current?.reset();
  }

  function openEditor(loc: Location) {
    setEditTarget(loc);
    setEditCapacity(loc.capacity);
    setEditTemp(loc.tempClass);
  }

  function saveEditor() {
    if (!editTarget) return;
    setLocations((prev) =>
      prev.map((l) =>
        l.id === editTarget.id
          ? { ...l, capacity: Math.max(l.onHand, editCapacity), tempClass: editTemp }
          : l
      )
    );
    setEditTarget(null);
  }

