      通路: l.aisle,
      区分: l.tempClass,
      SKU: l.sku?.sku ?? "",
      商品名: l.sku?.name ?? "",
      在庫数: l.onHand,
      容量: l.capacity,
      充填率: `${fillPct(l.onHand, l.capacity)}%`,
      状態: binState(l.onHand, l.capacity),
      滞留: isStale(l) ? "滞留" : "",
      最終移動日: l.lastMovedAt ?? "",
    }));
    downloadCsv(toCsv(data), "在庫ロケーション一覧.csv");
