  // ---- ScanGate stages: 移動元棚 → 商品 → 移動先棚 ----
  const stages: ScanGateStage[] = React.useMemo(
    () => [
      {
        id: "from",
        label: "① 移動元の棚をスキャン",
        title: "移動元",
        placeholder: "棚番バーコード（例 A-02-02）",
        onScan: (code): ScanGateResult => {
          const loc = locations.find((l) => l.id.toLowerCase() === code.trim().toLowerCase());
          if (!loc)
            return { ok: false, message: `棚番 ${code} が見つかりません。`, advance: "stay" };
          if (!loc.sku || loc.onHand <= 0)
            return { ok: false, message: `${loc.id} は空棚です。`, advance: "stay" };
          setFromId(loc.id);
          setToId("");
          setMoveQty(Math.min(loc.onHand, Math.max(1, Math.floor(loc.onHand / 2))));
          setMoveResult(null);
          return {
            ok: true,
            message: `移動元 ${loc.id}（${loc.sku.name}・在庫 ${loc.onHand}）を確認。`,
            value: loc.id,
          };
        },
      },
      {
        id: "item",
        label: "② 商品（JAN/SKU）をスキャン",
        title: "商品",
        placeholder: "JAN または SKU",
        onScan: (code, ctx): ScanGateResult => {
          const srcId = ctx.values["from"] as string | undefined;
          const src = srcId ? locations.find((l) => l.id === srcId) : null;
          if (!src || !src.sku)
            return { ok: false, message: "先に移動元の棚をスキャンしてください。", advance: "from" };
          const c = code.trim().toLowerCase();
          if (src.sku.sku.toLowerCase() !== c && src.sku.jan !== code.trim())
            return {
              ok: false,
              message: `スキャンした商品は ${src.id} の格納商品（${src.sku.name}）と一致しません。`,
              advance: "stay",
            };
          return { ok: true, message: `商品 ${src.sku.name} を確認。移動先をスキャンしてください。`, value: src.sku.sku };
        },
      },
      {
        id: "to",
        label: "③ 移動先の棚をスキャン",
        title: "移動先",
        placeholder: "棚番バーコード（例 A-02-01）",
        onScan: (code, ctx): ScanGateResult => {
          const srcId = ctx.values["from"] as string | undefined;
          const src = srcId ? locations.find((l) => l.id === srcId) : null;
          const dest = locations.find((l) => l.id.toLowerCase() === code.trim().toLowerCase());
          if (!dest)
            return { ok: false, message: `棚番 ${code} が見つかりません。`, advance: "stay" };
          if (src && dest.id === src.id)
            return { ok: false, message: "移動元と同じ棚です。別の棚をスキャンしてください。", advance: "stay" };
          if (src?.sku && dest.sku && dest.sku.sku !== src.sku.sku)
            return {
              ok: false,
              message: `${dest.id} には別商品（${dest.sku.name}）が入っています。`,
              advance: "stay",
            };
          if (dest.capacity - dest.onHand <= 0)
            return { ok: false, message: `${dest.id} に空き容量がありません。`, advance: "stay" };
          setToId(dest.id);
          return {
            ok: true,
            message: `移動先 ${dest.id} を確認。数量を入力して移動を実行してください。`,
            value: dest.id,
            advance: "stay", // hold on the last stage so the supervisor sets qty + commits
