            <div className="rounded-lg border border-border p-3">
              <p className="mb-2 text-sm font-medium">スキャンで確認</p>
              <ScanGate ref={scanRef} stages={stages} />
            </div>

            <Separator />

            {/* manual selection mirrors the scan state */}
            <div className="flex flex-col gap-3">
              <Select
                label="移動元の棚"
                value={fromId}
                onChange={(e) => {
                  setFromId(e.target.value);
                  setToId("");
                  const l = locations.find((x) => x.id === e.target.value);
                  if (l) setMoveQty(Math.min(l.onHand, Math.max(1, Math.floor(l.onHand / 2))));
                  setMoveResult(null);
                }}
              >
                <option value="">選択してください</option>
                {locations
                  .filter((l) => l.onHand > 0)
                  .map((l) => (
                    <option key={l.id} value={l.id}>
                      {l.id}（{l.sku?.name}・在庫 {l.onHand}）
                    </option>
                  ))}
              </Select>

              {from && from.sku ? (
                <div className="flex items-center gap-2 rounded-md bg-muted px-3 py-2 text-sm">
                  <IconPackage className="h-4 w-4 text-muted-foreground" aria-hidden="true" />
                  <span className="font-medium">{from.sku.name}</span>
                  <span className="font-mono text-xs text-muted-foreground">{from.sku.sku}</span>
                </div>
              ) : null}

              <Select
                label="移動先の棚"
                value={toId}
                onChange={(e) => setToId(e.target.value)}
                disabled={!from}
              >
                <option value="">選択してください</option>
                {destOptions.map((l) => (
                  <option key={l.id} value={l.id}>
                    {l.id}（{l.onHand <= 0 ? "空棚" : l.sku?.name}・空き {l.capacity - l.onHand}）
                  </option>
                ))}
              </Select>

              <div className="flex flex-col gap-1.5">
                <Label htmlFor="move-qty">移動数量</Label>
                <NumberInput
                  id="move-qty"
                  layout="stepper"
                  value={moveQty}
                  onValueChange={setMoveQty}
                  min={1}
                  max={from ? Math.min(from.onHand, to ? to.capacity - to.onHand : from.onHand) : 1}
                  aria-describedby="move-qty-hint"
                />
                <p id="move-qty-hint" className="text-xs text-muted-foreground">
                  {from
                    ? `移動元在庫 ${formatNumber(from.onHand)} 点` +
                      (to ? ` ／ 移動先空き ${formatNumber(destFree)} 点` : "")
                    : "移動元を選ぶと上限が決まります"}
                </p>
              </div>

              <Select
                label="移動理由"
                value={reason}
                onChange={(e) => setReason(e.target.value)}
              >
                {MOVE_REASONS.map((r) => (
                  <option key={r.value} value={r.value}>
                    {r.label}
                  </option>
                ))}
              </Select>
            </div>

            {/* preview: destination fill after move + net change */}
            {from && from.sku && to ? (
              <div className="flex flex-col gap-3 rounded-lg border border-border p-3">
                <p className="text-sm font-medium">移動プレビュー</p>
                <div className="grid grid-cols-1 gap-3 sm:grid-cols-2">
                  <div className="flex flex-col gap-1">
                    <span className="text-xs text-muted-foreground">移動元 {from.id}</span>
                    <LocationMeter
                      compact
                      onHand={from.onHand}
                      capacity={from.capacity}
                      name={`移動元 ${from.id}`}
                    />
                    <Delta
                      value={-moveQty}
                      labels={{ negative: "減少", zero: "変化なし" }}
                      tones={{ negative: "info" }}
                      showLabel
                      className="text-xs"
                    />
                    <span className="text-xs text-muted-foreground tabular-nums">
                      移動後 在庫 {formatNumber(Math.max(0, afterFromQty))}
                    </span>
                  </div>
                  <div className="flex flex-col gap-1">
                    <span className="text-xs text-muted-foreground">移動先 {to.id}</span>
                    <LocationMeter
                      compact
                      onHand={to.onHand}
                      capacity={to.capacity}
                      incoming={Math.min(moveQty, destFree)}
                      name={`移動先 ${to.id}`}
                    />
                    <Delta
                      value={moveQty}
                      labels={{ positive: "増加" }}
                      tones={{ positive: "info" }}
                      showLabel
                      className="text-xs"
                    />
                    <span className="text-xs text-muted-foreground tabular-nums">
                      移動後 在庫 {formatNumber(to.onHand + moveQty)} / 容量 {to.capacity}
                    </span>
                  </div>
                </div>
              </div>
            ) : null}

            {/* validation live region */}
            <div aria-live="polite">
              <Alert variant={validation.level}>
                {validation.level === "destructive" || validation.level === "warning" ? (
                  <IconAlertTriangle className="h-4 w-4" aria-hidden="true" />
                ) : validation.level === "success" ? (
                  <IconCircleCheck className="h-4 w-4" aria-hidden="true" />
                ) : (
                  <IconArrowRight className="h-4 w-4" aria-hidden="true" />
                )}
                <AlertTitle as="h3">
                  {validation.ok ? "移動の準備ができました" : "確認が必要です"}
                </AlertTitle>
                <AlertDescription>{validation.msg}</AlertDescription>
              </Alert>
            </div>
          </div>

          <SheetFooter className="border-t border-border px-4 py-3">
            <Button variant="outline" onClick={() => setMoveOpen(false)} className="gap-1">
              <IconX className="h-4 w-4" aria-hidden="true" />
              閉じる
            </Button>
            <Button onClick={commitMove} disabled={!validation.ok} className="gap-1">
              <IconArrowsExchange className="h-4 w-4" aria-hidden="true" />
              移動実行
            </Button>
          </SheetFooter>
        </SheetContent>
      </Sheet>

      {/* ───────── bin editor (Dialog) ───────── */}
      <Dialog open={editTarget !== null} onOpenChange={(o) => !o && setEditTarget(null)}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <IconEdit className="h-5 w-5 text-primary" aria-hidden="true" />
              ロケーション編集{editTarget ? ` — ${editTarget.id}` : ""}
            </DialogTitle>
            <DialogDescription>容量と温度区分を変更します。</DialogDescription>
          </DialogHeader>
          {editTarget ? (
            <div className="flex flex-col gap-4 py-2">
              <div className="flex flex-col gap-1.5">
                <Label htmlFor="edit-capacity">容量（最大格納数）</Label>
                <NumberInput
                  id="edit-capacity"
                  value={editCapacity}
                  onValueChange={setEditCapacity}
                  min={editTarget.onHand}
                  step={6}
                  aria-describedby="edit-capacity-hint"
                />
                <p id="edit-capacity-hint" className="text-xs text-muted-foreground">
                  現在の在庫 {formatNumber(editTarget.onHand)} 点未満には設定できません。
                </p>
              </div>
              <Select
                label="温度区分"
                value={editTemp}
                onChange={(e) => setEditTemp(e.target.value as TempClass)}
              >
                <option value="常温">常温</option>
                <option value="冷蔵">冷蔵</option>
                <option value="冷凍">冷凍</option>
                <option value="危険物">危険物</option>
              </Select>
            </div>
          ) : null}
          <DialogFooter>
            <Button variant="outline" onClick={() => setEditTarget(null)}>
              キャンセル
            </Button>
            <Button onClick={saveEditor}>保存</Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}
